#include<bits/stdc++.h>
using namespace std;
long long s[500010],f[500010],g[500010];
double slope(long long a,long long b)
{
    long long ax=s[a];
    long long bx=s[b];
    long long ay=g[a]+s[a]*s[a];
    long long by=g[b]+s[b]*s[b];
    if(ax==bx)
    {
        return -1e18;
    }
    return (by-ay)*1.0/(bx-ax);
}
int main()
{
    long long n,m;
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<=n;i++)
    {
        scanf("%lld",&s[i]);
        s[i]+=s[i-1];
        g[i]=s[i]*s[i];
    }
    for(long long p=1;p<m;p++)
    {
        deque<long long> q;
        q.push_back(p);
        for(long long i=p+1;i<=n;i++)
        {
            while(q.size()>1&&slope(q[0],q[1])<s[i]*2)
            {
                q.pop_front();
            }
            f[i]=0;
            if(!q.empty())
            {
                long long pre=q.front();
                f[i]=g[pre]+(s[i]-s[pre])*(s[i]-s[pre]);
            }
            while(q.size()>1&&slope(q.back(),q[q.size()-2])>slope(i,q.back()))
            {
                q.pop_back();
            }
            q.push_back(i);
        }
        memcpy(g,f,sizeof(f));
    }
    printf("%lld\n",f[n]*m-s[n]*s[n]);
    return 0;
}
